const sourceString = inputs['sourceString'];
const targetString = inputs['targetString'];
const script = inputs['script'];

// Escapes special characters in the provided string so it can be used safely in a regex.
function escapeRegExp(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Replaces all occurrences (global, case-insensitive) of searchString in text with replacement.
function replaceCaseInsensitive(text, searchString, replacement) {
  // Escape the search string to avoid special regex characters
  const escapedSearch = escapeRegExp(searchString);
  // Create a regex with the 'g' (global) and 'i' (case insensitive) flags
  const regex = new RegExp(escapedSearch, 'gi');
  return text.replace(regex, replacement);
}

const result = replaceCaseInsensitive(script, sourceString, targetString);

